  "code": "from typing import Dict, Any, Optional

class ProductCatalog:
    """Product catalog with caching."""

    def __init__(self) -> None:
        self._db: Dict[str, Dict[str, Any]] = {}
        self._cache: Dict[str, Dict[str, Any]] = {}

    def add_product(self, product_id: str, name: str, price: float) -> None:
        """Add a product to the database."""
        self._db[product_id] = {"name": name, "price": price}

    def get_product(self, product_id: str) -> Optional[Dict[str, Any]]:
        """Get product by ID, using cache for repeated lookups."""
        if product_id in self._cache:
            return self._cache[product_id]
        product = self._db.get(product_id)
        if product is not None:
            self._cache[product_id] = dict(product)
        return self._cache.get(product_id)

    def update_product(self, product_id: str, **fields: Any) -> bool:
        """Update product fields in the database.

        Invariant: get_product() must return current data after update.
        """
        if product_id not in self._db:
            return False
        self._db[product_id].update(fields)
        self._cache[product_id] = dict(self._db[product_id])  # Invalidate cache
        return True

    def reset(self) -> None:
        """Clear all data."""
        self._db.clear()
        self._cache.clear()"
}

